-- Main table to import sales data
CREATE TABLE import_ventes (
    id INT AUTO_INCREMENT PRIMARY KEY,
    date_transaction DATE,
    client_nom VARCHAR(255),
    client_prenom VARCHAR(255),
    client_email VARCHAR(255),
    client_ville VARCHAR(255),
    client_pays VARCHAR(255),
    client_code_postal VARCHAR(255),
    client_date_inscription DATE,
    produit_nom VARCHAR(255),
    produit_marque VARCHAR(255),
    produit_prix DECIMAL(10, 2),
    produit_disponibilite VARCHAR(50),
    adresse_livraison TEXT,
    montant DECIMAL(10, 2)
);

